# system_card_registry.py — maintains the AI system inventory

import json
from pathlib import Path
import datetime

REGISTRY_PATH = Path("system-cards/registry.json")

def register_system_card(card_meta: dict):
    registry = json.loads(REGISTRY_PATH.read_text()) if REGISTRY_PATH.exists() else {"systems": []}
    existing_ids = {s["system_card_id"] for s in registry["systems"]}
    if card_meta["system_card_id"] in existing_ids:
        registry["systems"] = [
            card_meta if s["system_card_id"] == card_meta["system_card_id"] else s
            for s in registry["systems"]
        ]
    else:
        registry["systems"].append(card_meta)
    REGISTRY_PATH.write_text(json.dumps(registry, indent=2))
    print(f"Registered: {card_meta['system_card_id']}")

def overdue_reviews(today: datetime.date = None) -> list[dict]:
    today = today or datetime.date.today()
    registry = json.loads(REGISTRY_PATH.read_text())
    return [
        s for s in registry["systems"]
        if s.get("status") == "active"
        and datetime.date.fromisoformat(s.get("next_review_due", "2099-01-01")) < today
    ]
